import type { Activity, NutritionEntry, FoodLibraryItem, OFFProduct } from '../index.js';

export const HEALTH_EVENTS = {
    ADD_WORKOUT: 'health:add-workout',
    ADD_FOOD: 'health:add-food',
    EDIT_FOOD: 'health:edit-food',
    EDIT_WORKOUT: 'health:edit-workout',
    SCAN_BARCODE: 'health:scan-barcode',
    AI_ESTIMATE: 'health:ai-estimate',
    LOG_FOOD: 'health:log-food',
    SELECT_LIBRARY_ITEM: 'health:select-library-item',
    SELECT_OFF_ITEM: 'health:select-off-item',
    LOAD_MORE_OFF: 'health:load-more-off',
    FOOD_LOG_BACK: 'health:food-log-back',
} as const;

export interface HealthEventMap {
    [HEALTH_EVENTS.ADD_WORKOUT]: { date: string };
    [HEALTH_EVENTS.ADD_FOOD]: { date: string; meal: string };
    [HEALTH_EVENTS.EDIT_FOOD]: { entry: NutritionEntry };
    [HEALTH_EVENTS.EDIT_WORKOUT]: { activity: Activity };
    [HEALTH_EVENTS.SCAN_BARCODE]: void;
    [HEALTH_EVENTS.AI_ESTIMATE]: void;
    [HEALTH_EVENTS.LOG_FOOD]: NutritionEntry; // Or a subset depending on usage
    [HEALTH_EVENTS.SELECT_LIBRARY_ITEM]: FoodLibraryItem;
    [HEALTH_EVENTS.SELECT_OFF_ITEM]: OFFProduct;
    [HEALTH_EVENTS.LOAD_MORE_OFF]: void;
    [HEALTH_EVENTS.FOOD_LOG_BACK]: void;
}

export type HealthEvent<K extends keyof HealthEventMap> = CustomEvent<HealthEventMap[K]>;
